27	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
28	
29	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
30	
31	const isMainItem = (item: Item): boolean => !isComponent(item);
32	
33	const groupByType = (items: Item[]): Map<string, number> =>
34	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
35	
36	const componentGroupPremium = (type: string, count: number): number =>
37	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
38	
39	const componentsPremium = (items: Item[]): number =>
40	  Array.from(groupByType(items.filter(isComponent)))
41	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
42	
43	const isHighlyEnchanted = (item: Item): boolean =>
44	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
45	
