47	
48	const applySurcharge = (base: number, rate: number): number => base * (1 + rate);
49	
50	const itemSurcharge = (item: Item): number =>
51	  surchargeWhen(item.cursed === true, CURSED_SURCHARGE) +
52	  surchargeWhen(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE);
