57	const mainItemsPremium = (items: Item[]): number =>
58	  items.filter(isMainItem)
59	    .reduce((sum, item) => sum + itemPremium(item), 0);
60	
61	const itemsPremium = (items: Item[]): number =>
62	  mainItemsPremium(items) + componentsPremium(items);
63	
64	const isLongStanding = (customer: Customer): boolean =>
